def expo_mod(b: int, e: int, m: int) -> int:
    new_b = b % m
    answer = 1
    while e > 0:
        if e % 2 == 1:
            answer = (answer * new_b) % m
        new_b = (new_b ** 2) % m
        e = e // 2
    return answer

def text_to_ascii(filename: str) -> list[int]:
    # read the and convert to ascii
    ord_list = []
    with open(filename, 'r') as file:
        for line in file:
            for c in line:
                ord_list.append(ord(c))
                
    # split the list into 214 byte blocks
    start = 0
    end = len(ord_list)
    step = 214
    split_lists = []
    for i in range(start, end, step):
        x = i
        split_lists.append(ord_list[x:x+step])

    list_ints = []
    for l in split_lists:
        sum = 0
        counter = len(l) - 1
        for i in range(len(l)):
            sum += l[i] * (256 ** counter)
            counter -= 1
        list_ints.append(sum)
    return list_ints

def encrypt(filename: str, public_key: tuple) -> list[int]:
    #take in the file and the key, then encrypts and returns as a list
    n, e = public_key
    list_ints = text_to_ascii(filename)
    ciphertexts = []
    for m in list_ints:
        ciphertexts.append(expo_mod(m, e, n))
    return ciphertexts

def int_to_string(n: int) -> str:
    # turns the int into a string
    chars = []
    while n > 0:
        chars.append(chr(n % 256))
        n //= 256
    return ''.join(reversed(chars))

def decrypt(ciphertext_file: str, d: int, public_key: tuple) -> str:
    # takes in file and key, then decrypts and returns as a string
    n, _ = public_key
    decrypted_message = []
    with open(ciphertext_file, 'r') as cip:
        for line in cip:
            c = int(line.strip())
            m = expo_mod(c, d, n)
            decrypted_message.append(int_to_string(m))
    return ''.join(decrypted_message)

